# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import pickle
import base64
import boto3
from datetime import datetime

def lambda_handler(event, context):
    try:
        body = json.loads(event['body']) if isinstance(event.get('body'), str) else event.get('body', {})
        
        event_type = body.get('event_type')
        event_data = body.get('data', {})
        partner_id = body.get('partner_id')
        timestamp = body.get('timestamp', datetime.utcnow().isoformat())
        
        pickled_data = pickle.dumps(event_data)
        encoded_data = base64.b64encode(pickled_data).decode('utf-8')
        
        processed_event = {
            'partner_id': partner_id,
            'event_type': event_type,
            'serialized_data': encoded_data,
            'timestamp': timestamp,
            'processed_at': datetime.utcnow().isoformat()
        }
        
        dynamodb = boto3.resource('dynamodb')
        table = dynamodb.Table('WebhookEvents')
        table.put_item(Item=processed_event)
        
        if encoded_data:
            decoded_pickled = base64.b64decode(encoded_data)
            unpickled_data = pickle.loads(decoded_pickled)
            
            process_user_action(unpickled_data, event_type, partner_id)
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'message': 'Webhook processed successfully',
                'event_id': f"{partner_id}_{timestamp}"
            })
        }
    
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'message': 'Error processing webhook',
                'error': str(e)
            })
        }


def process_user_action(data, event_type, partner_id):
    sqs = boto3.client('sqs')
    queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/user-actions-queue'
    
    action_mapping = {
        'user_signup': process_signup,
        'user_login': process_login,
        'user_purchase': process_purchase,
        'user_profile_update': process_profile_update
    }
    
    if event_type in action_mapping:
        action_mapping[event_type](data, partner_id)
    
    message_body = {
        'event_type': event_type,
        'partner_id': partner_id,
        'data': data,
        'processed_at': datetime.utcnow().isoformat()
    }
    
    sqs.send_message(
        QueueUrl=queue_url,
        MessageBody=json.dumps(message_body)
    )


def process_signup(data, partner_id):
    print(f"Processing signup for partner {partner_id}: {data.get('user_email')}")
    
    dynamodb = boto3.resource('dynamodb')
    users_table = dynamodb.Table('Users')
    
    user_item = {
        'user_id': data.get('user_id'),
        'email': data.get('user_email'),
        'partner_id': partner_id,
        'signup_date': data.get('signup_date', datetime.utcnow().isoformat()),
        'user_metadata': data.get('metadata', {})
    }
    
    users_table.put_item(Item=user_item)


def process_login(data, partner_id):
    print(f"Processing login for partner {partner_id}: {data.get('user_id')}")
    
    dynamodb = boto3.resource('dynamodb')
    activity_table = dynamodb.Table('UserActivity')
    
    activity_item = {
        'user_id': data.get('user_id'),
        'activity_type': 'login',
        'partner_id': partner_id,
        'timestamp': data.get('login_time', datetime.utcnow().isoformat()),
        'ip_address': data.get('ip_address'),
        'device_info': data.get('device_info', {})
    }
    
    activity_table.put_item(Item=activity_item)


def process_purchase(data, partner_id):
    print(f"Processing purchase for partner {partner_id}: {data.get('order_id')}")
    
    dynamodb = boto3.resource('dynamodb')
    orders_table = dynamodb.Table('Orders')
    
    order_item = {
        'order_id': data.get('order_id'),
        'user_id': data.get('user_id'),
        'partner_id': partner_id,
        'amount': data.get('amount'),
        'currency': data.get('currency', 'USD'),
        'items': data.get('items', []),
        'purchase_date': data.get('purchase_date', datetime.utcnow().isoformat())
    }
    
    orders_table.put_item(Item=order_item)


def process_profile_update(data, partner_id):
    print(f"Processing profile update for partner {partner_id}: {data.get('user_id')}")
    
    dynamodb = boto3.resource('dynamodb')
    users_table = dynamodb.Table('Users')
    
    update_expression = "SET "
    expression_values = {}
    
    for key, value in data.get('updated_fields', {}).items():
        update_expression += f"{key} = :{key}, "
        expression_values[f":{key}"] = value
    
    update_expression = update_expression.rstrip(', ')
    
    if expression_values:
        users_table.update_item(
            Key={'user_id': data.get('user_id')},
            UpdateExpression=update_expression,
            ExpressionAttributeValues=expression_values
        )